@prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a schema1:PropertyValue ;
                    schema1:propertyID "DOI" ;
                    schema1:url "https://doi.org/10.12345/xas-optional-test" ;
                    schema1:value "10.12345/xas-optional-test" ] ;
            sh:resultMessage "Node Literal(\"DOI\") does not conform to one or more shapes in [ sh:nodeKind sh:IRI ] , [ sh:datatype xsd:string ; sh:minLength Literal(\"5\", datatype=xsd:integer) ] , [ sh:class schema1:DefinedTerm ]" ;
            sh:resultPath schema1:propertyID ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:OrConstraintComponent ;
            sh:sourceShape [ sh:minCount 1 ;
                    sh:or ( [ sh:nodeKind sh:IRI ] [ sh:datatype xsd:string ;
                                sh:minLength 5 ] [ sh:class schema1:DefinedTerm ] ) ;
                    sh:path schema1:propertyID ;
                    sh:severity sh:Warning ] ;
            sh:value "DOI" ] .

