[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/person_jdoe> ;
            sh:resultMessage "A maintainer or provider Person should have a contactPoint for users to reach" ;
            sh:resultPath schema1:contactPoint ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A maintainer or provider Person should have a contactPoint for users to reach" ;
                    sh:minCount 1 ;
                    sh:or ( [ sh:class schema1:ContactPoint ] [ sh:nodeKind sh:IRI ] ) ;
                    sh:path schema1:contactPoint ;
                    sh:severity sh:Warning ] ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/person_jdoe> ;
            sh:resultMessage "A Person should have a contactPoint (schema:ContactPoint or mailto: IRI)" ;
            sh:resultPath schema1:contactPoint ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:contactPointProperty ] .

